const { BigQuery } = require('@google-cloud/bigquery');
const crypto = require('crypto');

const bigquery = new BigQuery();

const ALLOWED_DATASETS = process.env.ALLOWED_DATASETS ? process.env.ALLOWED_DATASETS.split(',') : [];
const ALLOWED_TABLES = process.env.ALLOWED_TABLES ? process.env.ALLOWED_TABLES.split(',') : [];
const MAX_ROWS_PER_BATCH = 10000;
const ENCRYPTION_KEY = process.env.ENCRYPTION_KEY || crypto.randomBytes(32).toString('hex');

function validateInput(input) {
  if (!input || typeof input !== 'object') {
    throw new Error('Invalid input format');
  }

  const { datasetId, tableId, aggregationType, groupByFields, aggregateFields } = input;

  if (!datasetId || typeof datasetId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(datasetId)) {
    throw new Error('Invalid dataset ID');
  }

  if (!tableId || typeof tableId !== 'string' || !/^[a-zA-Z0-9_]+$/.test(tableId)) {
    throw new Error('Invalid table ID');
  }

  if (ALLOWED_DATASETS.length > 0 && !ALLOWED_DATASETS.includes(datasetId)) {
    throw new Error('Dataset not allowed');
  }

  if (ALLOWED_TABLES.length > 0 && !ALLOWED_TABLES.includes(tableId)) {
    throw new Error('Table not allowed');
  }

  const validAggregations = ['SUM', 'AVG', 'COUNT', 'MIN', 'MAX'];
  if (!aggregationType || !validAggregations.includes(aggregationType.toUpperCase())) {
    throw new Error('Invalid aggregation type');
  }

  if (groupByFields && !Array.isArray(groupByFields)) {
    throw new Error('groupByFields must be an array');
  }

  if (groupByFields) {
    for (const field of groupByFields) {
      if (typeof field !== 'string' || !/^[a-zA-Z0-9_]+$/.test(field)) {
        throw new Error('Invalid field name in groupByFields');
      }
    }
  }

  if (aggregateFields && !Array.isArray(aggregateFields)) {
    throw new Error('aggregateFields must be an array');
  }

  if (aggregateFields) {
    for (const field of aggregateFields) {
      if (typeof field !== 'string' || !/^[a-zA-Z0-9_]+$/.test(field)) {
        throw new Error('Invalid field name in aggregateFields');
      }
    }
  }

  return { datasetId, tableId, aggregationType, groupByFields, aggregateFields };
}

function sanitizeIdentifier(identifier) {
  return identifier.replace(/[^a-zA-Z0-9_]/g, '');
}

function buildQuery(datasetId, tableId, aggregationType, groupByFields, aggregateFields) {
  const sanitizedDataset = sanitizeIdentifier(datasetId);
  const sanitizedTable = sanitizeIdentifier(tableId);
  
  let selectClause = '';
  let groupByClause = '';

  if (groupByFields && groupByFields.length > 0) {
    const sanitizedGroupFields = groupByFields.map(f => sanitizeIdentifier(f));
    selectClause = sanitizedGroupFields.join(', ') + ', ';
    groupByClause = ` GROUP BY ${sanitizedGroupFields.join(', ')}`;
  }

  if (aggregateFields && aggregateFields.length > 0) {
    const sanitizedAggFields = aggregateFields.map(f => sanitizeIdentifier(f));
    const aggClauses = sanitizedAggFields.map(field => 
      `${aggregationType}(${field}) as ${field}_${aggregationType.toLowerCase()}`
    );
    selectClause += aggClauses.join(', ');
  } else {
    selectClause += `${aggregationType}(*) as total_${aggregationType.toLowerCase()}`;
  }

  const query = `SELECT ${selectClause} FROM \`${sanitizedDataset}.${sanitizedTable}\`${groupByClause}`;
  
  return query;
}

async function processDataInBatches(datasetId, tableId, aggregationType, groupByFields, aggregateFields) {
  const query = buildQuery(datasetId, tableId, aggregationType, groupByFields, aggregateFields);
  
  console.log(`Executing query: ${query}`);
  
  const options = {
    query: query,
    location: 'US',
    maximumBytesBilled: '10000000000',
    useLegacySql: false,
    timeoutMs: 500000
  };

  const [job] = await bigquery.createQueryJob(options);
  console.log(`Job ${job.id} started.`);

  const [rows] = await job.getQueryResults({
    maxResults: MAX_ROWS_PER_BATCH,
    autoPaginate: true
  });

  console.log(`Query completed. Retrieved ${rows.length} rows.`);
  
  return rows;
}

function encryptSensitiveData(data) {
  const algorithm = 'aes-256-cbc';
  const key = Buffer.from(ENCRYPTION_KEY, 'hex').slice(0, 32);
  const iv = crypto.randomBytes(16);
  
  const cipher = crypto.createCipheriv(algorithm, key, iv);
  let encrypted = cipher.update(JSON.stringify(data), 'utf8', 'hex');
  encrypted += cipher.final('hex');
  
  return {
    encrypted: encrypted,
    iv: iv.toString('hex')
  };
}

function aggregateResults(rows, aggregationType) {
  const summary = {
    totalRows: rows.length,
    aggregationType: aggregationType,
    timestamp: new Date().toISOString(),
    data: rows
  };

  return summary;
}

exports.processBigData = async (req, res) => {
  const startTime = Date.now();
  
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.set('Content-Security-Policy', "default-src 'none'");

  try {
    if (req.method !== 'POST') {
      res.status(405).json({ error: 'Method not allowed' });
      return;
    }

    const authHeader = req.get('Authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      res.status(401).json({ error: 'Unauthorized: Missing or invalid authorization header' });
      return;
    }

    const token = authHeader.substring(7);
    if (!token || token.length < 32) {
      res.status(401).json({ error: 'Unauthorized: Invalid token' });
      return;
    }

    const validatedInput = validateInput(req.body);
    const { datasetId, tableId, aggregationType, groupByFields, aggregateFields } = validatedInput;

    console.log(`Processing dataset: ${datasetId}, table: ${tableId}`);
    console.log(`Memory limit: 8GB, Timeout: 540 seconds`);

    const rows = await processDataInBatches(
      datasetId, 
      tableId, 
      aggregationType, 
      groupByFields, 
      aggregateFields
    );

    const results = aggregateResults(rows, aggregationType);
    
    const encryptedResults = encryptSensitiveData(results);

    const processingTime = Date.now() - startTime;
    console.log(`Processing completed in ${processingTime}ms`);

    res.status(200).json({
      success: true,
      processingTimeMs: processingTime,
      rowCount: results.totalRows,
      encryptedData: encryptedResults.encrypted,
      iv: encryptedResults.iv,
      message: 'Data processed successfully'
    });

  } catch (error) {
    console.error('Error processing data:', error);
    
    const safeErrorMessage = error.message.replace(/[<>\"']/g, '');
    
    res.status(500).json({
      success: false,
      error: 'Internal server error',
      message: safeErrorMessage,
      timestamp: new Date().toISOString()
    });
  }
};